```class Solution {
    public int minimumChanges(String s, int k) {
        int n = s.length();
        int res = Integer.MAX_VALUE;
        for (int i = 1; i <= n / 2; i++) {
            if (n % i == 0) {
                int changes = 0;
                for (int j = 0; j < n; j += i) {
                    String group = s.substring(j, Math.min(j + i, n));
                    changes += (group.length() % 2 == 1) ? 1 : 0;
                }
                res = Math.min(res, changes);
            }
        }
        return res;
    }
}```
